// src/routes/webhook.ts
init_services();
init_brevo();
var webhookRoutes = new Z0({ prefix: "/api/webhook" }).post("/stripe", async ({ request }) => {
  const payload = await request.text();
  const signature = request.headers.get("stripe-signature");
  if (!signature) {
    return new Response(JSON.stringify({ error: "Falta firma" }), {
      status: 400,
      headers: { "Content-Type": "application/json" }
    });
  }
  let event;
  try {
    event = stripe.webhooks.constructEvent(payload, signature, process.env.STRIPE_WEBHOOK_SECRET);
  } catch {
    return new Response(JSON.stringify({ error: "Firma inv\xE1lida" }), {
      status: 400,
      headers: { "Content-Type": "application/json" }
    });
  }
  if (event.type === "checkout.session.completed") {
    const session = event.data.object;
    const email = session.customer_details?.email;
    const customerName = session.customer_details?.name;
    const tipo = session.metadata?.tipo;
    console.log(`
========== WEBHOOK STRIPE ==========`);
    console.log("Evento: checkout.session.completed");
    console.log("Session ID:", session.id);
    console.log("Tipo:", tipo || "pedido");
    console.log("Customer Email:", email);
    console.log("Customer Name:", customerName);
    console.log("Amount Total:", session.amount_total);
    console.log(`====================================
`);
    if (tipo === "receta") {
      const recetaId = session.metadata?.recetaId;
      if (recetaId) {
        console.log(`[WEBHOOK] Confirmando pago de receta: ${recetaId}`);
        await recetaService.aceptar(recetaId);
        console.log(`[WEBHOOK] Receta ${recetaId} marcada como ACEPTADA`);
      }
    } else {
      if (email) {
        console.log("[WEBHOOK] Confirmando pago y enviando factura...");
        const pedido3 = await pedidoService.confirmarPagoConEmail(session.id, email);
        if (pedido3) {
          console.log(`[WEBHOOK] Pedido confirmado ID: ${pedido3._id.toString()}`);
          console.log(`[WEBHOOK] Enviando factura a ${email}...`);
          await enviarFacturaPedido({
            email,
            nombre: customerName || "Cliente",
            pedidoId: pedido3._id.toString(),
            total: pedido3.total,
            items: pedido3.items.map((item) => ({
              nombre: item.nombre,
              cantidad: item.cantidad,
              precioSnapshot: item.precioSnapshot
            })),
            metodoEntrega: pedido3.metodoEntrega,
            direccionEnvio: pedido3.direccionEnvio
          });
        } else {
          console.log("[WEBHOOK] \u274C No se encontr\xF3 pedido para esta session");
        }
      } else {
        console.log("[WEBHOOK] No hay email del cliente, solo se confirma pago");
        await pedidoService.confirmarPago(session.id);
      }
    }
  }
  return { received: true };
});
