init_models();
init_cloudinary();
async function listPasteles(context) {
  const { set: set2, query } = context;
  const q = {};
  const { search } = query;
  if (search) {
    q.$or = [
      { nombre: new RegExp(search, "i") },
      { descripcion: new RegExp(search, "i") }
    ];
  }
  const page = query.page || 1;
  const limit = 100;
  const skip = (page - 1) * limit;
  const [pasteles, total] = await Promise.all([
    Pastel.find(q).skip(skip).limit(limit),
    Pastel.countDocuments(q)
  ]);
  set2.status = 200;
  return { pasteles, total, page, limit };
}
async function createPastel(context) {
  const { set: set2, body } = context;
  console.log("[CREATE PASTEL] Body:", JSON.stringify(body));
  const pastelData = {
    nombre: body.nombre,
    descripcion: body.descripcion || "",
    precio: body.precio,
    imagen: body.imagen || "",
    categoria: body.categoria || "general",
    disponible: true
  };
  const pastel3 = await Pastel.create(pastelData);
  const plainPastel = pastel3.toObject();
  const result = {
    _id: plainPastel._id.toString(),
    nombre: plainPastel.nombre,
    descripcion: plainPastel.descripcion,
    precio: plainPastel.precio,
    imagen: plainPastel.imagen,
    categoria: plainPastel.categoria,
    disponible: plainPastel.disponible,
    createdAt: plainPastel.createdAt?.toISOString(),
    updatedAt: plainPastel.updatedAt?.toISOString()
  };
  console.log("[CREATE PASTEL] Result:", JSON.stringify(result));
  set2.status = 201;
  return result;
}
async function updatePastel(context) {
  const { set: set2, params, body } = context;
  const pastel3 = await Pastel.findByIdAndUpdate(params.id, { $set: { ...body, updatedAt: new Date } }, { new: true });
  if (!pastel3) {
    set2.status = 404;
    return { error: "Pastel no encontrado" };
  }
  set2.status = 200;
  return pastel3;
}
async function deletePastel(context) {
  const { set: set2, params } = context;
  const pastel3 = await Pastel.findById(params.id);
  if (!pastel3) {
    set2.status = 404;
    return { error: "Pastel no encontrado" };
  }
  if (pastel3.imagen) {
    const publicId = extraerPublicId(pastel3.imagen);
    if (publicId) {
      try {
        await eliminarImagen(publicId);
        console.log("[DELETE PASTEL] Imagen eliminada de Cloudinary:", publicId);
      } catch (error3) {
        console.error("[DELETE PASTEL] Error eliminando imagen:", error3);
      }
    }
  }
  await Pastel.findByIdAndDelete(params.id);
  set2.status = 200;
  return { success: true };
}

// src/controllers/admin/pedidoController.ts
init_models();
var allowedTransitions = {
  PENDIENTE: ["PAGADO", "CANCELADO"],
  PAGADO: ["PREPARANDO", "CANCELADO"],
  PREPARANDO: ["LISTO", "CANCELADO"],
  LISTO: ["EN_CAMINO", "CANCELADO"],
  EN_CAMINO: ["ENTREGADO", "CANCELADO"],
  ENTREGADO: [],
  CANCELADO: []
};
async function listPedidos(context) {
  const { set: set2, query } = context;
  const { status, date: date3 } = query;
  const q = {};
  if (status)
    q.estado = status;
  if (date3) {
    const startDate = new Date(date3);
    q.createdAt = {
      $gte: startDate,
      $lt: new Date(startDate.getTime() + 86400000)
    };
  }
  const pedidos = await Pedido.find(q);
  set2.status = 200;
  return pedidos;
}
async function updatePedidoStatus(context) {
  const { set: set2, params, body } = context;
  const newStatus = body.status;
  const pedido3 = await Pedido.findById(params.id);
  if (!pedido3) {
    set2.status = 404;
    return { error: "Pedido no encontrado" };
  }
  if (!allowedTransitions[pedido3.estado]?.includes(newStatus)) {
    set2.status = 400;
    return { error: `Transici\xF3n no v\xE1lida de ${pedido3.estado} a ${newStatus}` };
  }
  const result = await Pedido.findByIdAndUpdate(params.id, { $set: { estado: newStatus, updatedAt: new Date } }, { new: true });
  set2.status = 200;
  return result;
}

