async function autoSeed() {
  try {
    const count = await Pastel.countDocuments();
    if (count === 0) {
      console.log("\uD83C\uDF31 Base de datos vac\xEDa, ejecutando seed autom\xE1tico...");
      await Pastel.insertMany(PASTELES_DATA);
      console.log(`\u2705 Seed completado: ${PASTELES_DATA.length} pasteles insertados`);
    } else {
      console.log(`\u2139\uFE0F Base de datos tiene ${count} pasteles, seed omitido`);
    }
  } catch (error3) {
    console.error("\u274C Error en auto-seed:", error3);
  }
}
var app = new Z0().use(cors({
  origin: process.env.FRONTEND_URL || "http://localhost:3000",
  credentials: true
})).onRequest(({ request }) => {
  const url = new URL(request.url);
  console.log(`[BACKEND REQUEST] ${request.method} ${url.pathname}${url.search}`, {
    timestamp: new Date().toISOString(),
    hasAuthHeader: !!request.headers.get("authorization"),
    contentType: request.headers.get("content-type"),
    origin: request.headers.get("origin")
  });
}).onError(({ code, error: error3, set: set2 }) => {
  console.error("[BACKEND ERROR]", { code, error: error3.message });
  set2.status = code === "NOT_FOUND" ? 404 : 500;
  return { error: error3.message || "Internal Server Error" };
}).get("/health", () => ({ status: "ok", timestamp: new Date().toISOString() })).use(pastelRoutes).use(pedidoRoutes).use(recetaRoutes).use(webhookRoutes).use(adminRoutes).use(uploadRoutes).use(usuarioRoutes);
var PORT = parseInt(process.env.PORT || "3001");
if (true) {
  async function start() {
    try {
      await connectDB();
      console.log("\u2705 Base de datos conectada");
      await autoSeed();
      app.listen(PORT, () => {
        console.log(`\uD83D\uDE80 Servidor corriendo en http://localhost:${PORT}`);
      });
    } catch (error3) {
      console.error("\u274C Error al iniciar:", error3);
      process.exit(1);
    }
  }
  start();
}
export {
  app
};
